props.content:
Menu {
    Button("QR Code", systemImage: "qrcode") { showQRCode = true }
    Button("Share Profile", systemImage: "square.and.arrow.up") { showShareProfile = true }
    Button("Analytics", systemImage: "chart.bar.fill") { /* nav */ }
    Button("Credits", systemImage: "creditcard.fill") { /* nav */ }
    Divider()
    Button("Settings", systemImage: "gearshape.fill") { /* nav */ }
} label: {
    Image(systemName: "ellipsis.circle")
        .foregroundStyle(ClawTokColors.textTertiary)
}

{
  "tool_type": "text_to_video",
  "model_preference": "runway_gen4",
  "input": {
    "prompt": "A golden retriever surfing on a rainbow wave",
    "duration": 5,
    "aspect_ratio": "9:16"
  },
  "callback_url": "https://api.clawtok.com/webhooks/inference-complete",
  "idempotency_key": "uuid-v4",
  "priority": "standard"
}

